/* ==========================================================================
   UTILITIES LAYER
   Helper classes. These have the highest layer priority.
   ========================================================================== */

@layer utilities {
  /* Visually hidden -- accessible to screen readers but not visible.
   * Uses the clip technique for reliable hiding.
   * white-space: nowrap prevents content from being announced as
   * multiple separate items by some screen readers. */
  .visually-hidden,
  .sr-only {
    position: absolute;
    inline-size: 1px;
    block-size: 1px;
    padding: 0;
    margin: -1px;
    overflow: hidden;
    clip: rect(0 0 0 0);
    clip-path: inset(50%);
    white-space: nowrap;
    border: 0;
  }

  /* Skip link -- visually hidden until focused, then revealed.
   * Keyboard users tab to this first and see it appear at the
   * top of the page. Uses the base template's skip link:
   * <a href="#main-content" class="skip-link">Skip to main content</a> */
  .skip-link {
    position: absolute;
    inline-size: 1px;
    block-size: 1px;
    padding: 0;
    margin: -1px;
    overflow: hidden;
    clip: rect(0 0 0 0);
    clip-path: inset(50%);
    white-space: nowrap;
    border: 0;

    &:focus-visible {
      position: fixed;
      inset-block-start: var(--space-sm);
      inset-inline-start: var(--space-sm);
      z-index: 9999;
      inline-size: auto;
      block-size: auto;
      padding: var(--space-sm) var(--space-md);
      margin: 0;
      overflow: visible;
      clip: auto;
      clip-path: none;
      white-space: normal;
      background-color: var(--color-primary);
      color: white;
      font-size: var(--font-size-sm);
      font-weight: var(--font-medium);
      border-radius: var(--radius-md);
      box-shadow: var(--shadow-md);
    }
  }
}

{% extends "base.html" %}

{% block title %}Next Actions -- Todo List{% endblock %}

{% block nav %}
{% include "gtd_nav.html" %}
{% endblock %}

{% block content %}
<div class="next-actions">
    <h1>Next Actions</h1>

    {% if let Some(error) = error_message %}
    <div class="next-actions__error" role="alert">{{ error }}</div>
    {% endif %}

    <div id="next-actions-content">
    <nav class="next-actions__filters" aria-label="Filter by context">
        <ul class="next-actions__filter-list" role="list">
            <li>
                <a href="/next-actions"
                    hx-get="/next-actions"
                    hx-target="#next-actions-content"
                    hx-select="#next-actions-content"
                    hx-swap="outerHTML"
                    hx-push-url="true"
                    {% if selected_context.is_none() %}aria-current="true" class="next-actions__filter-link next-actions__filter-link--active"{% else %}class="next-actions__filter-link"{% endif %}>All</a>
            </li>
            {% for ctx in contexts %}
            <li>
                <a href="/next-actions?context={{ ctx.id }}"
                    hx-get="/next-actions?context={{ ctx.id }}"
                    hx-target="#next-actions-content"
                    hx-select="#next-actions-content"
                    hx-swap="outerHTML"
                    hx-push-url="true"
                    {% if selected_context.as_deref() == Some(ctx.id.as_str()) %}aria-current="true" class="next-actions__filter-link next-actions__filter-link--active"{% else %}class="next-actions__filter-link"{% endif %}>{{ ctx.name }}</a>
            </li>
            {% endfor %}
        </ul>
    </nav>

    {% if !contexts.is_empty() %}
    <form
        method="post"
        action="/next-actions"
        class="next-actions__add"
        hx-post="/next-actions"
        hx-target="#next-actions-list"
        hx-swap="beforeend"
        hx-on::after-request="if(event.detail.successful) { this.querySelector('#next-action-title').value = ''; this.querySelector('#next-action-title').focus(); }"
    >
        <label for="next-action-title">Add next action</label>
        <div class="next-actions__add-row">
            <input
                type="text"
                id="next-action-title"
                name="title"
                placeholder="What's the next action?"
                maxlength="300"
                autocomplete="off"
                class="next-actions__add-input"
            >
            <label for="next-action-context" class="next-actions__context-label">Context</label>
            <select id="next-action-context" name="context_id" class="next-actions__add-context">
                {% for ctx in contexts %}
                <option value="{{ ctx.id }}"{% if selected_context.as_deref() == Some(ctx.id.as_str()) %} selected{% endif %}>{{ ctx.name }}</option>
                {% endfor %}
            </select>
            <button type="submit" class="next-actions__add-submit">Add</button>
        </div>
    </form>
    {% endif %}

    {% if groups.is_empty() %}
    <div class="next-actions__empty-state" id="next-actions-empty-state">
        <p>No next actions yet. Process your <a href="/inbox">inbox</a> to find things to do.</p>
    </div>
    {% endif %}
    <div id="next-actions-list"{% if groups.is_empty() %} hidden{% endif %}>
        {% if selected_context.is_none() %}
        {% for group in groups %}
        <section class="next-actions__group" aria-labelledby="context-heading-{{ group.context_id }}">
            <h2 id="context-heading-{{ group.context_id }}" class="next-actions__context-heading">{{ group.context_name }}</h2>
            <ul class="next-actions__list" role="list">
                {% for action in group.actions %}
                {% include "next_action_item.html" %}
                {% endfor %}
            </ul>
        </section>
        {% endfor %}
        {% else %}
        <ul class="next-actions__list" role="list">
            {% for group in groups %}
            {% for action in group.actions %}
            {% include "next_action_item.html" %}
            {% endfor %}
            {% endfor %}
        </ul>
        {% endif %}
    </div>
    </div>
</div>
{% endblock %}

{% block scripts %}
<script src="/static/js/next-action-focus.js"></script>
{% endblock %}

{% extends "base.html" %}

{% block title %}Projects -- Todo List{% endblock %}

{% block nav %}
{% include "gtd_nav.html" %}
{% endblock %}

{% block content %}
<div class="projects">
    <h1>Projects</h1>

    {% if let Some(error) = error_message %}
    <div class="projects__error" role="alert">{{ error }}</div>
    {% endif %}

    <form
        method="post"
        action="/projects"
        class="projects__add"
        hx-post="/projects"
        hx-target="#projects-list"
        hx-swap="beforeend"
        hx-on::after-request="if(event.detail.successful) { this.querySelector('#project-title').value = ''; this.querySelector('#project-title').focus(); }"
    >
        <label for="project-title">Add project</label>
        <div class="projects__add-row">
            <input
                type="text"
                id="project-title"
                name="title"
                placeholder="What outcome are you working toward?"
                maxlength="300"
                autocomplete="off"
                class="projects__add-input"
            >
            <button type="submit" class="projects__add-submit">Add</button>
        </div>
    </form>

    {% if projects.is_empty() %}
    <div class="projects__empty-state" id="projects-empty-state">
        <p>No projects yet. Projects are outcomes that need more than one step. You can create one here or during inbox processing.</p>
    </div>
    {% endif %}
    <ul class="projects__list" role="list" id="projects-list"{% if projects.is_empty() %} hidden{% endif %}>
        {% for project in projects %}
        {% include "project_item.html" %}
        {% endfor %}
    </ul>
</div>
{% endblock %}

{% block scripts %}
<script src="/static/js/project-focus.js"></script>
{% endblock %}

